import React, { useState, useContext } from "react";
// Remove { Link } from here
import { GeneralContext } from "./GeneralContext";
import "./BuyActionWindow.css";

const BuyActionWindow = ({ uid }) => {
  const [stockQuantity, setStockQuantity] = useState(1);
  const [stockPrice, setStockPrice] = useState(0.0);

  const { handleCloseBuyWindow } = useContext(GeneralContext);

  const handleBuyClick = () => {
    console.log(`Ordered: ${uid}, Qty: ${stockQuantity}, Price: ${stockPrice}`);
    handleCloseBuyWindow();
  };

  return (
    <div className="container" id="buy-window">
      <div className="inputs">
        <fieldset>
          <legend>Qty.</legend>
          <input
            type="number"
            onChange={(e) => setStockQuantity(e.target.value)}
            value={stockQuantity}
          />
        </fieldset>
        <fieldset>
          <legend>Price</legend>
          <input
            type="number"
            step="0.05"
            onChange={(e) => setStockPrice(e.target.value)}
            value={stockPrice}
          />
        </fieldset>
      </div>

      <div className="buttons">
        <span>Margin required ₹140.45</span>
        <div>
          <button className="btn btn-blue" onClick={handleBuyClick}>
            Buy
          </button>
          <button className="btn btn-grey" onClick={handleCloseBuyWindow}>
            Cancel
          </button>
        </div>
      </div>
    </div>
  );
};

export default BuyActionWindow;
